mapper.update:
UPDATE ai_chat_sessions
SET current_round = #{currentRound},
    current_stage = 'conversation',
    last_message_at = #{lastMessageAt},
    remark = NULL,
    updated_by = #{studentId},
    update_time = #{now}
WHERE session_id = #{sessionId}
  AND student_id = #{studentId}
  AND delete_flag = '1'

UPDATE ai_chat_sessions
SET last_message_at = #{lastMessageAt},
    updated_by = #{studentId},
    update_time = #{now}
WHERE session_id = #{sessionId}
  AND student_id = #{studentId}
  AND delete_flag = '1'

UPDATE ai_chat_sessions
SET current_stage = #{currentStage},
    session_status = 'active',
    remark = #{remark},
    updated_by = #{studentId},
    update_time = #{now}
WHERE session_id = #{sessionId}
  AND student_id = #{studentId}
  AND delete_flag = '1'

UPDATE ai_chat_sessions
SET collected_slots_json = #{collectedSlotsJson},
    missing_dimensions_json = #{missingDimensionsJson},
    current_stage = #{currentStage},
    updated_by = #{studentId},
    update_time = #{now}
WHERE session_id = #{sessionId}
  AND student_id = #{studentId}
  AND delete_flag = '1'

mapper.select:
SELECT id, message_role, message_type, sequence_no, content, create_time
FROM ai_chat_messages
WHERE session_id = #{sessionId}
  AND delete_flag = '1'
  AND is_visible = 1

  AND id < #{beforeId}

ORDER BY id DESC
LIMIT #{limit}
